document.addEventListener("DOMContentLoaded",(()=>{document.querySelectorAll('.nav-toggle').forEach(btn=>{btn.addEventListener('click',()=>{const inner=btn.closest('.nav-inner');const expanded=btn.getAttribute('aria-expanded')==='true';btn.setAttribute('aria-expanded',String(!expanded));inner.classList.toggle('open');});});const navInner=document.querySelector('.nav-inner');if(navInner){navInner.querySelectorAll('a').forEach(a=>{a.addEventListener('click',()=>{navInner.classList.remove('open');const toggle=navInner.querySelector('.nav-toggle');if(toggle)toggle.setAttribute('aria-expanded','false');});});const path=location.pathname.split('/').pop()||'index.html';navInner.querySelectorAll('a').forEach(a=>{const href=a.getAttribute('href');if(href===path)a.classList.add('active');});}const skip=document.querySelector('.skip-link');if(skip){skip.addEventListener('click',(e)=>{const main=document.getElementById('main-content');if(main){e.preventDefault();main.setAttribute('tabindex','-1');main.focus({preventScroll:false});window.scrollTo({top:main.offsetTop-8,behavior:'smooth'});}});} }));
